import React from "react";
import jwt_decode from 'jwt-decode';
import { useDispatch } from "react-redux";
import userActions from "../redux/actions/userActions";
import { useEffect } from "react";


export default function GoogleSignUp() {
    const dispatch = useDispatch();


    async function handleCallbackResponse(response) {
        console.log(response.credntial);
        let userObject = jwt_decode(response.credential);
        console.log(userObject)
        dispatch(userActions.signUpUser({
            fullname: userObject.given_name.family_name,
            photo: userObject.picture,
            email: userObject.email,
            password: userObject.jti,
            from: "google"
        }))
    }

    useEffect(() => {
        google.accounts.id.initialize({
            client_id: '661563449445-sngehoe8ps1e2u3me7ivljeeh5m1ej1b.apps.googleusercontent.com',
            callback: handleCallbackResponse
        });

        google.accounts.id.renderButton(
            document.getElementById('buttonDiv'),
            { theme: "outline", size:"medium" }
        )
    });

    return(
        <div>
            <div id="buttonDiv"></div>
        </div>
    )
}
